class Solution:
    def countDigitOne(self, n):
        if n < 1:
            return 0
        count = 0
        i = 1
        while i <= n:
            divider = i * 10
            higher = n // divider
            cur = (n // i) % 10
            lower = n % i
            if cur == 0:
                count += higher * i
            elif cur == 1:
                count += higher * i + (lower + 1)
            else:
                count += (higher + 1) * i
            i *= 10
        return count

solutions.javascript:
var countDigitOne = function(n) {
    if (n < 1) return 0;
    let count = 0;
    for (let i = 1; i <= n; i *= 10) {
        const divider = i * 10;
        const higher = Math.floor(n / divider);
        const cur = Math.floor(n / i) % 10;
        const lower = n % i;
        if (cur === 0) {
            count += higher * i;
        } else if (cur === 1) {
            count += higher * i + (lower + 1);
        } else {
            count += (higher + 1) * i;
        }
    }
    return count;
};
